classDiagram
  class DataSource {
    <<abstract>>
    +connect()
    +fetchData()
  }
  class PubMedSource {
    +connect()
    +fetchData()
  }
  class ClinicalTrialsSource {
    +connect()
    +fetchData()
  }
  class GenBankSource {
    +connect()
    +fetchData()
  }
  class Transformable {
    <<interface>>
    +transform(data)
  }
  class DataCleaner {
    +transform(data)
    +removeNulls()
    +normalizeFields()
    +deduplicate()
  }
  class FeatureExtractor {
    +transform(data)
    +extractKeywords()
    +computeMetrics()
  }
  class DataSink {
    <<abstract>>
    +persist(data)
  }
  class PostgresSink {
    +persist(data)
  }
  class S3Sink {
    +persist(data)
  }
  class Pipeline {
    +DataSource[] sources
    +Transformable[] transformers
    +DataSink sink
    +run()
    +validate()
    +getStatus()
  }
  DataSource <|-- PubMedSource
  DataSource <|-- ClinicalTrialsSource
  DataSource <|-- GenBankSource
  Transformable <|.. DataCleaner
  Transformable <|.. FeatureExtractor
  DataSink <|-- PostgresSink
  DataSink <|-- S3Sink
  Pipeline *-- DataSource
  Pipeline o-- Transformable
  Pipeline *-- DataSink
